INSERT INTO branches (id, name, location, address, phone, email, description, image_url, rating, status, latitude, longitude, is_active, created_at, updated_at) VALUES
(1, "T'Pizza Hai Bà Trưng", 'Hồ Chí Minh', '180 Hai Bà Trưng, Phường Đa Kao, Quận 1, TP. HCM', '028 3622 0500', 'haibatrung@tpizza.com', 'Chi nhánh trung tâm cổ kính, trang nhã. Có quầy bar dài lãng mạn và hai lò nướng củi trung tâm rực lửa.', 'https://images.unsplash.com/photo-1555396273-367ea4eb4db5?auto=format&fit=crop&w=800&q=80', 4.8, 'active', 10.782800, 106.695800, 1, NOW(), NOW()),
(2, "T'Pizza Võ Văn Tần", 'Hồ Chí Minh', '31 Võ Văn Tần, Phường 6, Quận 3, TP. HCM', '028 3622 0501', 'vovantan@tpizza.com', 'Phong cách sân vườn biệt thự Đông Dương cũ. Không gian ngoài trời ngập tràn bóng mát cây xanh.', 'https://images.unsplash.com/photo-1517248135467-4c7edcad34c4?auto=format&fit=crop&w=800&q=80', 4.9, 'active', 10.778500, 106.690800, 1, NOW(), NOW()),
(3, "T'Pizza Lý Quốc Sư", 'Hà Nội', '2 Lý Quốc Sư, Hàng Trống, Hoàn Kiếm, Hà Nội', '024 3622 0502', 'lyquocsu@tpizza.com', 'Nằm ngay sát Nhà Thờ Lớn cổ kính. Không gian gác mái ấm cúng với gạch mộc và dầm gỗ tự nhiên.', 'https://images.unsplash.com/photo-1551882547-ff40c63fe5fa?auto=format&fit=crop&w=800&q=80', 4.7, 'active', 21.028900, 105.848800, 1, NOW(), NOW()),
(4, "T'Pizza Phan Chu Trinh", 'Hà Nội', '43 Phan Chu Trinh, Hoàn Kiếm, Hà Nội', '024 3622 0503', 'phanchutrinh@tpizza.com', 'Không gian mở 2 tầng rộng lớn, phong cách Tây Âu kết hợp tối giản Nhật Bản.', 'https://images.unsplash.com/photo-1414235077428-338989a2e8c0?auto=format&fit=crop&w=800&q=80', 4.8, 'busy', 21.021500, 105.856200, 1, NOW(), NOW()),
(5, "T'Pizza Bạch Đằng", 'Đà Nẵng', '214 Bạch Đằng, Phước Ninh, Hải Châu, Đà Nẵng', '0236 3622 0504', 'bachdang@tpizza.com', 'Ôm trọn tầm nhìn ra Sông Hàn và Cầu Rồng thơ mộng. Khu vực seating ngoài trời lộng gió.', 'https://images.unsplash.com/photo-1544025162-d76694265947?auto=format&fit=crop&w=800&q=80', 4.9, 'active', 16.066400, 108.223800, 1, NOW(), NOW()),
(6, "T'Pizza Điện Biên Phủ", 'Hải Phòng', '15 Điện Biên Phủ, Máy Tơ, Ngô Quyền, Hải Phòng', '0225 3622 0505', 'dienbienphu@tpizza.com', 'Thiết kế cải tạo từ một nhà kho hải cảng cũ, kiến trúc thô mộc Industrial đầy cuốn hút.', 'https://images.unsplash.com/photo-1554118811-1e0d58224f24?auto=format&fit=crop&w=800&q=80', 4.6, 'active', 20.865400, 106.689200, 1, NOW(), NOW());
