((SELECT id FROM chat_sessions WHERE session_id='demo_session_001'), 'assistant', 'Chào bạn! 🖐️ Tôi là trợ lý T''Pizza. Tôi có thể giúp gì cho bạn?', 'greeting', '{}', DATE_SUB(NOW(), INTERVAL 1 DAY)),
((SELECT id FROM chat_sessions WHERE session_id='demo_session_001'), 'user', 'Cho tôi xem thực đơn', 'menu', '{}', DATE_SUB(NOW(), INTERVAL 1 DAY)),
((SELECT id FROM chat_sessions WHERE session_id='demo_session_001'), 'assistant', '🍕 **Thực đơn T''Pizza gợi ý:**\n\n• Pizza lò củi: Margherita, Prosciutto, Burrata\n• Mỳ Ý: Spaghetti Carbonara\n• Đồ uống: Bia thủ công, Vang Ý', 'menu', '{}', DATE_SUB(NOW(), INTERVAL 1 DAY));
